sql:
SELECT History_Notes
FROM medical_histories
WHERE patient_id = 1;

external_knowledge:
- The phrase "top 3 symptoms" refers to the 3 symptoms with the highest counts for each disease; 
- The phrase "most common symptoms" implies the symptoms that appear most frequently for a given disease; 
- "Patients suffering from each disease" corresponds to the unique patients associated with each disease in the medical histories.

sql:
SELECT substance_name
FROM pharmacological_substances
WHERE Side_Effects IS NOT NULL;

SELECT disease_name, Prevalence
FROM diseases
ORDER BY Prevalence DESC;

SELECT COUNT(*) AS procedure_count
FROM diagnostic_procedures
WHERE disease_id = 0;

SELECT MAX(Last_Updated) AS Latest_Update
FROM laboratory_results
WHERE test_name = 'Lipid Panel';

SELECT COUNT(DISTINCT patient_id) AS total_patients
FROM medical_histories
WHERE disease_id = (SELECT disease_id FROM diseases WHERE disease_name = 'Congestive heart failure');
